+async function runExecProcess(opts: {
+  command: string;
+  workdir: string;
+  env: Record<string, string>;
+  sandbox?: BashSandboxConfig;
+  containerWorkdir?: string | null;
+  usePty: boolean;
+  warnings: string[];
+  maxOutput: number;
+  pendingMaxOutput: number;
+  notifyOnExit: boolean;
+  scopeKey?: string;
+  sessionKey?: string;
+  timeoutSec: number;
+  onUpdate?: (partialResult: AgentToolResult<ExecToolDetails>) => void;
+}): Promise<ExecProcessHandle> {
+  const startedAt = Date.now();
+  const sessionId = createSessionSlug();
+  let child: ChildProcessWithoutNullStreams | null = null;
+  let pty: PtyHandle | null = null;
+  let stdin: SessionStdin | undefined;
+
+  if (opts.sandbox) {
+    child = spawn(
+      "docker",
+      buildDockerExecArgs({
+        containerName: opts.sandbox.containerName,
+        command: opts.command,
+        workdir: opts.containerWorkdir ?? opts.sandbox.containerWorkdir,
+        env: opts.env,
+        tty: opts.usePty,
+      }),
+      {
+        cwd: opts.workdir,
+        env: process.env,
+        detached: process.platform !== "win32",
+        stdio: ["pipe", "pipe", "pipe"],
+        windowsHide: true,
+      },
+    ) as ChildProcessWithoutNullStreams;
+    stdin = child.stdin;
+  } else if (opts.usePty) {
+    const ptyModule = (await import("@lydell/node-pty")) as unknown as {
+      spawn?: PtySpawn;
+      default?: { spawn?: PtySpawn };
+    };
+    const spawnPty = ptyModule.spawn ?? ptyModule.default?.spawn;
+    if (!spawnPty) {
+      throw new Error("PTY support is unavailable (node-pty spawn not found).");
+    }
+    const { shell, args: shellArgs } = getShellConfig();
+    pty = spawnPty(shell, [...shellArgs, opts.command], {
+      cwd: opts.workdir,
+      env: opts.env,
+      name: process.env.TERM ?? "xterm-256color",
+      cols: 120,
+      rows: 30,
+    });
+    stdin = {
+      destroyed: false,
+      write: (data, cb) => {
+        try {
+          pty?.write(data);
+          cb?.(null);
+        } catch (err) {
+          cb?.(err as Error);
+        }
+      },
+      end: () => {
+        try {
+          const eof = process.platform === "win32" ? "\x1a" : "\x04";
+          pty?.write(eof);
+        } catch {
+          // ignore EOF errors
+        }
+      },
+    };
+  } else {
+    const { shell, args: shellArgs } = getShellConfig();
+    child = spawn(shell, [...shellArgs, opts.command], {
+      cwd: opts.workdir,
+      env: opts.env,
+      detached: process.platform !== "win32",
+      stdio: ["pipe", "pipe", "pipe"],
+      windowsHide: true,
+    }) as ChildProcessWithoutNullStreams;
+    stdin = child.stdin;
+  }
+
+  const session = {
+    id: sessionId,
+    command: opts.command,
+    scopeKey: opts.scopeKey,
+    sessionKey: opts.sessionKey,
+    notifyOnExit: opts.notifyOnExit,
+    exitNotified: false,
+    child: child ?? undefined,
+    stdin,
+    pid: child?.pid ?? pty?.pid,
+    startedAt,
+    cwd: opts.workdir,
+    maxOutputChars: opts.maxOutput,
+    pendingMaxOutputChars: opts.pendingMaxOutput,
+    totalOutputChars: 0,
+    pendingStdout: [],
+    pendingStderr: [],
+    pendingStdoutChars: 0,
+    pendingStderrChars: 0,
+    aggregated: "",
+    tail: "",
+    exited: false,
+    exitCode: undefined as number | null | undefined,
+    exitSignal: undefined as NodeJS.Signals | number | null | undefined,
+    truncated: false,
+    backgrounded: false,
+  } satisfies ProcessSession;
+  addSession(session);
+
+  let settled = false;
+  let timeoutTimer: NodeJS.Timeout | null = null;
+  let timeoutFinalizeTimer: NodeJS.Timeout | null = null;
+  let timedOut = false;
+  const timeoutFinalizeMs = 1000;
+  let resolveFn: ((outcome: ExecProcessOutcome) => void) | null = null;
+
+  const settle = (outcome: ExecProcessOutcome) => {
+    if (settled) return;
+    settled = true;
+    resolveFn?.(outcome);
+  };
+
+  const finalizeTimeout = () => {
+    if (session.exited) return;
+    markExited(session, null, "SIGKILL", "failed");
+    maybeNotifyOnExit(session, "failed");
+    const aggregated = session.aggregated.trim();
+    const reason = `Command timed out after ${opts.timeoutSec} seconds`;
+    settle({
+      status: "failed",
+      exitCode: null,
+      exitSignal: "SIGKILL",
+      durationMs: Date.now() - startedAt,
+      aggregated,
+      timedOut: true,
+      reason: aggregated ? `${aggregated}\n\n${reason}` : reason,
+    });
+  };
+
+  const onTimeout = () => {
+    timedOut = true;
+    killSession(session);
+    if (!timeoutFinalizeTimer) {
+      timeoutFinalizeTimer = setTimeout(() => {
+        finalizeTimeout();
+      }, timeoutFinalizeMs);
+    }
+  };
+
+  if (opts.timeoutSec > 0) {
+    timeoutTimer = setTimeout(() => {
+      onTimeout();
+    }, opts.timeoutSec * 1000);
+  }
+
+  const emitUpdate = () => {
+    if (!opts.onUpdate) return;
+    const tailText = session.tail || session.aggregated;
+    const warningText = opts.warnings.length ? `${opts.warnings.join("\n")}\n\n` : "";
+    opts.onUpdate({
+      content: [{ type: "text", text: warningText + (tailText || "") }],
+      details: {
+        status: "running",
+        sessionId,
+        pid: session.pid ?? undefined,
+        startedAt,
+        cwd: session.cwd,
+        tail: session.tail,
+      },
+    });
+  };
+
+  const handleStdout = (data: string) => {
+    const str = sanitizeBinaryOutput(data.toString());
+    for (const chunk of chunkString(str)) {
+      appendOutput(session, "stdout", chunk);
+      emitUpdate();
+    }
+  };
+
+  const handleStderr = (data: string) => {
+    const str = sanitizeBinaryOutput(data.toString());
+    for (const chunk of chunkString(str)) {
+      appendOutput(session, "stderr", chunk);
+      emitUpdate();
+    }
+  };
+
+  if (pty) {
+    const cursorResponse = buildCursorPositionResponse();
+    pty.onData((data) => {
+      const raw = data.toString();
+      const { cleaned, requests } = stripDsrRequests(raw);
+      if (requests > 0) {
+        for (let i = 0; i < requests; i += 1) {
+          pty.write(cursorResponse);
+        }
+      }
+      handleStdout(cleaned);
+    });
+  } else if (child) {
+    child.stdout.on("data", handleStdout);
+    child.stderr.on("data", handleStderr);
+  }
+
+  const promise = new Promise<ExecProcessOutcome>((resolve) => {
+    resolveFn = resolve;
+    const handleExit = (code: number | null, exitSignal: NodeJS.Signals | number | null) => {
+      if (timeoutTimer) clearTimeout(timeoutTimer);
+      if (timeoutFinalizeTimer) clearTimeout(timeoutFinalizeTimer);
+      const durationMs = Date.now() - startedAt;
+      const wasSignal = exitSignal != null;
+      const isSuccess = code === 0 && !wasSignal && !timedOut;
+      const status: "completed" | "failed" = isSuccess ? "completed" : "failed";
+      markExited(session, code, exitSignal, status);
+      maybeNotifyOnExit(session, status);
+      if (!session.child && session.stdin) {
+        session.stdin.destroyed = true;
+      }
+
+      if (settled) return;
+      const aggregated = session.aggregated.trim();
+      if (!isSuccess) {
+        const reason = timedOut
+          ? `Command timed out after ${opts.timeoutSec} seconds`
+          : wasSignal && exitSignal
+            ? `Command aborted by signal ${exitSignal}`
+            : code === null
+              ? "Command aborted before exit code was captured"
+              : `Command exited with code ${code}`;
+        const message = aggregated ? `${aggregated}\n\n${reason}` : reason;
+        settle({
+          status: "failed",
+          exitCode: code ?? null,
+          exitSignal: exitSignal ?? null,
+          durationMs,
+          aggregated,
+          timedOut,
+          reason: message,
+        });
+        return;
+      }
+      settle({
+        status: "completed",
+        exitCode: code ?? 0,
+        exitSignal: exitSignal ?? null,
+        durationMs,
+        aggregated,
+        timedOut: false,
+      });
+    };
+
+    if (pty) {
+      pty.onExit((event) => {
+        const rawSignal = event.signal ?? null;
+        const normalizedSignal = rawSignal === 0 ? null : rawSignal;
+        handleExit(event.exitCode ?? null, normalizedSignal);
+      });
+    } else if (child) {
+      child.once("close", (code, exitSignal) => {
+        handleExit(code, exitSignal);
+      });
+
+      child.once("error", (err) => {
+        if (timeoutTimer) clearTimeout(timeoutTimer);
+        if (timeoutFinalizeTimer) clearTimeout(timeoutFinalizeTimer);
+        markExited(session, null, null, "failed");
+        maybeNotifyOnExit(session, "failed");
+        const aggregated = session.aggregated.trim();
+        const message = aggregated ? `${aggregated}\n\n${String(err)}` : String(err);
+        settle({
+          status: "failed",
+          exitCode: null,
+          exitSignal: null,
+          durationMs: Date.now() - startedAt,
+          aggregated,
+          timedOut,
+          reason: message,
+        });
+      });
+    }
+  });
+
+  return {
+    session,
+    startedAt,
+    pid: session.pid ?? undefined,
+    promise,
+    kill: () => killSession(session),
+  };
+}
